#define BUTTON_PIN 2  
#define LED_PIN 13   

int StatusGelb = 0;

void setup()
{
  pinMode(LED_PIN, OUTPUT);


  pinMode(BUTTON_PIN, INPUT);
}

void loop()
{

  StatusGelb = digitalRead(BUTTON_PIN);


  if (StatusGelb == HIGH)
  {
    digitalWrite(LED_PIN, HIGH);
  }
  else
  {
    digitalWrite(LED_PIN, LOW);
  }
}

