#include <Stepper.h>
#include <Adafruit_NeoPixel.h>

// Anzahl der Schritte pro Umdrehung
#define STEPS      2048
// Motorgeschwindigkeit in RPM
#define MOTOR_RPM     6
Stepper stepper(STEPS, 8, 10, 9, 11); // Motor Pins

#define PIN           3
#define NUMPIXELS    24
Adafruit_NeoPixel pixels(NUMPIXELS, PIN, NEO_GRB + NEO_KHZ800);

int position = 0;

void setup()
{
    pinMode(8, OUTPUT);
    pinMode(9, OUTPUT);
    pinMode(10, OUTPUT);
    pinMode(11, OUTPUT);
    pinMode(11, OUTPUT);
    pinMode(2, INPUT_PULLUP);

    Serial.begin(9600);
    Serial.println("Motor startet");

    pixels.begin();
    pixels.clear();

    stepper.setSpeed(MOTOR_RPM);
    int steps = 8;
    int counter = 0;
    // Generiere 3 Drehungen
    // Überwache den Endlagensensor im Polling Mode und aktiviere den LED Ring
    while (counter < 3 * STEPS) {
        stepper.step(steps);
        position=position+steps;
        if (digitalRead(2) == 0) {
          for (int i=0; i<NUMPIXELS; i++)
            pixels.setPixelColor(i, pixels.Color(0, 150, 0));
          pixels.show();
        } else {
          pixels.clear();
          pixels.show();
        }
        counter += 3;
        Serial.println(counter);
    }
    Serial.println("3 Runden absolviert");
}

void loop()
{
}

